#include<bits/stdc++.h>
using namespace std;
const int maxn=2e2+5;
int n,a[maxn],ans2,dp2[maxn][maxn];
signed main() {
	ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);
	cin>>n;
	for(int i=1;i<=n;i++){
		cin>>a[i];
		a[i+n]=a[i];
	}
	for(int l=2;l<=n;l++){
		for(int i=1,j;(j=i+l-1)<=2*n;i++){
			dp2[i][j]=0;
			for(int k=i;k<j;k++){
				dp2[i][j]=max(dp2[i][j],dp2[i][k]+dp2[k+1][j]+a[k+1]*a[i]*a[j+1]);
			}
		}
	}
	for(int i=1;i<=n;i++){
		ans2=max(ans2,dp2[i][i+n-1]);
	}
	cout<<ans2;
	return 0;
}
